      "name": "IngestData",
      "governance": {
        "error_handling": {
          "strategy": "fail_fast",
          "description": "If source is invalid or parsing fails, return error immediately without writing to raw_data."
        },
        "retry_policy": {
          "max_retries": 0,
          "description": "No retry; ingestion is idempotent per call."
